def gen(rng, size):
    n = max(2, min(size, 1500))
    nums = []
    for _ in range(n):
        if rng.random() < 0.45:
            nums.append(1)
        else:
            nums.append(rng.choice([2, 3, 4, 5, 6]))
    forbidden = []
    for i in range(n):
        if nums[i] == 1 and rng.random() < 0.9:
            forbidden.append(1)
        else:
            forbidden.append(rng.choice([1, 2, 3, 4, 5, 6]))
    return [nums, forbidden]

