class Solution:
    def minSwaps(self, nums, forbidden):
        n = len(nums)
        cnt = {}
        for v in nums:
            cnt[v] = cnt.get(v, 0) + 1
        fcnt = {}
        for v in forbidden:
            fcnt[v] = fcnt.get(v, 0) + 1
        for v, c in cnt.items():
            if c + fcnt.get(v, 0) > n:
                return -1
        bad_count = {}
        b = 0
        for i in range(n):
            if nums[i] == forbidden[i]:
                b += 1
                bad_count[nums[i]] = bad_count.get(nums[i], 0) + 1
        if b == 0:
            return 0
        m_max = max(bad_count.values())
        return max((b + 1) // 2, m_max)

