var minSwaps = function(nums, forbidden) {
    const n = nums.length;
    const cnt = new Map();
    for (const v of nums) cnt.set(v, (cnt.get(v) || 0) + 1);
    const fcnt = new Map();
    for (const v of forbidden) fcnt.set(v, (fcnt.get(v) || 0) + 1);
    for (const [v, c] of cnt) {
        if (c + (fcnt.get(v) || 0) > n) return -1;
    }
    const badCount = new Map();
    let b = 0;
    for (let i = 0; i < n; i++) {
        if (nums[i] === forbidden[i]) {
            b += 1;
            badCount.set(nums[i], (badCount.get(nums[i]) || 0) + 1);
        }
    }
    if (b === 0) return 0;
    let mMax = 0;
    for (const c of badCount.values()) mMax = Math.max(mMax, c);
    return Math.max(Math.ceil(b / 2), mMax);
};
